    "description": "A list of pet objects.",
    "schema": {
      "type": "array",
      "items": {
        "$ref": "#/definitions/Pet"
      }
    }
  }
}
```

but got

```json
"get": {
  "description": "Get the list of pets.",
  "responses": {
